// Manual asset step (`just og-graphs`) — NOT part of `pnpm build`, since it shells out to
// rsvg-convert which the CI runner doesn't have. Like the og-icon, the PNGs are committed and
// regenerated by hand when the FSM data changes; `vite build` then copies static/og/→build/og/, and
// gen-og-pages.mjs points each FSM favorite's og:image at the committed graph.
//
// Renders each curated favorite's FSM state graph to a 1200×630 PNG. Deduped by content hash, since
// many favorites can share a model. Output: static/og/graph-<hash>.png.
//
// The graph is produced by the SAME pure layout + presentational component the live view uses
// (src/lib/graph/{layout.ts,GraphSvg.svelte}), rendered headless via svelte/server. Because a
// standalone rasterised SVG can't resolve the app's CSS custom properties (rsvg-convert/librsvg
// doesn't propagate `var(--…)` or support `color-mix()`), we inline concrete hex colours read from
// src/app.css: `var(--…)` is string-replaced, `color-mix(in srgb, …)` is computed, and the
// class-based colours are supplied via an injected <style> block with concrete hex.
//
// Resilient: missing data/content is warned and skipped so the build never fails here.

import { readFile, mkdir, copyFile } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import { spawn } from 'node:child_process';
import path from 'node:path';
import { createServer } from 'vite';
import { svelte } from '@sveltejs/vite-plugin-svelte';

// pipe an SVG string through rsvg-convert (stdin) to a PNG file
const rsvg = (svg, outPath) =>
	new Promise((resolve, reject) => {
		const p = spawn('rsvg-convert', ['-o', outPath]);
		let err = '';
		p.stderr.on('data', (d) => (err += d));
		p.on('error', reject);
		p.on('close', (code) =>
			code === 0 ? resolve() : reject(new Error(`rsvg-convert exit ${code}: ${err}`))
		);
		p.stdin.on('error', () => {}); // ignore EPIPE if the child died early
		p.stdin.end(svg);
	});

const DATA = 'static/data';
const OUT = 'static/og'; // persistent, committed; `vite build` copies static/og/ → build/og/
// if a build already exists, also drop the freshly rendered PNGs straight into it, so regenerating
// graphs is reflected in a served build without a full rebuild
const BUILD_OUT = 'build/og';

// concrete palette (src/app.css :root) — a standalone SVG can't resolve the app's CSS vars
const VARS = {
	'--bg': '#1a1b1e',
	'--panel': '#232428',
	'--fg': '#e6e6e6',
	'--dim': '#8b8d92',
	'--accent': '#6cb6ff',
	'--event': '#e5c07b',
	'--state': '#56b6c2',
	'--action': '#98c379',
	'--var': '#c678dd'
};
const BG = VARS['--bg'];
const MONO = 'ui-monospace, Menlo, monospace';

// class-based colours from GraphSvg's <style> (svelte/server render() doesn't emit component CSS, so
// we redefine the visible rules here with concrete hex; :hover/.sel/.hot aren't reachable in a static
// unselected render). Unscoped selectors still match the elements' base class names.
const STYLE = `
    .node { fill: ${VARS['--panel']}; stroke: #555; stroke-width: 1; }
    .node.start { stroke: ${VARS['--state']}; stroke-width: 2; }
    .node.any { fill: #2a2333; stroke: ${VARS['--var']}; }
    .nlabel { fill: ${VARS['--state']}; font-family: ${MONO}; font-size: 13px; }
    .elabel { fill: ${VARS['--event']}; font-family: ${MONO}; font-size: 11px; paint-order: stroke; stroke: ${BG}; stroke-width: 3px; }
    .erow { fill: ${VARS['--event']}; font-family: ${MONO}; font-size: 11px; }
    .port { fill: #888; }
    .wire { fill: none; stroke: #4a4a4a; stroke-width: 1; }
    .chain-divider { stroke: #444; stroke-width: 1; }
    .node-slot { fill: transparent; }
    .chain-slot { fill: transparent; }
    .chain-arrow { fill: ${VARS['--dim']}; font-family: ${MONO}; font-size: 10px; }
    .chain-event { fill: ${VARS['--event']}; font-family: ${MONO}; font-size: 10px; opacity: 0.7; }`;

const mix = (a, pct, b) => {
	const h = (c) => [1, 3, 5].map((i) => parseInt(c.slice(i, i + 2), 16));
	const [ar, ag, ab] = h(a);
	const [br, bg, bb] = h(b);
	const t = pct / 100;
	const m = (x, y) => Math.round(x * t + y * (1 - t));
	const hex = (n) => n.toString(16).padStart(2, '0');
	return `#${hex(m(ar, br))}${hex(m(ag, bg))}${hex(m(ab, bb))}`;
};

// replace CSS vars, then compute any color-mix() that survives (e.g. the node tint fill)
function inlineColors(svg) {
	let s = svg.replace(/var\((--[a-z]+)(?:,\s*[^)]*)?\)/g, (m, name) => VARS[name] ?? m);
	s = s.replace(
		/color-mix\(in srgb,\s*(#[0-9a-fA-F]{6})\s+(\d+)%,\s*(#[0-9a-fA-F]{6})\)/g,
		(_m, c1, pct, c2) => mix(c1, Number(pct), c2)
	);
	return s;
}

const expandIndex = (raw) =>
	raw.e.map(([fi, name, game_object, hash], id) => ({ id, file: raw.f[fi], name, game_object, hash }));

async function main() {
	const server = await createServer({
		configFile: false,
		logLevel: 'error',
		appType: 'custom',
		server: { middlewareMode: true },
		optimizeDeps: { noDiscovery: true },
		plugins: [svelte()],
		resolve: { alias: { $lib: path.resolve('src/lib') } }
	});

	let GAMES, computeLayout, GraphSvg, render;
	try {
		({ GAMES } = await server.ssrLoadModule(path.resolve('src/lib/config.ts')));
		({ computeLayout } = await server.ssrLoadModule(path.resolve('src/lib/graph/layout.ts')));
		GraphSvg = (await server.ssrLoadModule(path.resolve('src/lib/graph/GraphSvg.svelte'))).default;
		({ render } = await server.ssrLoadModule('svelte/server'));
	} finally {
		await server.close();
	}

	await mkdir(OUT, { recursive: true });
	const toBuild = existsSync('build');
	if (toBuild) await mkdir(BUILD_OUT, { recursive: true });

	const done = new Set(); // content hashes already rasterised (dedupe)
	let favoritesWithFsm = 0;
	const skipped = [];

	for (const g of GAMES) {
		const favorites = (g.favorites ?? []).filter((f) => f.fsm);
		if (!favorites.length) continue;
		const indexPath = path.join(DATA, g.id, 'index.json');
		if (!existsSync(indexPath)) {
			console.warn(`gen-og-graphs: ${indexPath} missing (data not unpacked?) — skipping ${g.id}`);
			continue;
		}
		const entries = expandIndex(JSON.parse(await readFile(indexPath, 'utf8')));

		for (const f of favorites) {
			favoritesWithFsm++;
			const e = entries.find(
				(x) => x.file === f.file && x.game_object === (f.game_object ?? '') && x.name === f.fsm
			);
			if (!e) {
				skipped.push(`${g.id}/${f.name} (fsm not found)`);
				continue;
			}
			if (done.has(e.hash)) continue;
			const contentPath = path.join(DATA, g.id, 'content', `${e.hash}.json`);
			if (!existsSync(contentPath)) {
				skipped.push(`${g.id}/${f.name} (content ${e.hash} missing)`);
				continue;
			}
			const model = JSON.parse(await readFile(contentPath, 'utf8'));

			// match the app default (edgeStyle 'side', collapseChains true)
			const layout = computeLayout(model, { edgeStyle: 'side', collapseChains: true });
			const { body } = render(GraphSvg, {
				props: { layout, edgeStyle: 'side', selected: null }
			});

			// fit the layout into the 1200×630 frame edge-to-edge; never upscale a small graph past 1.0
			const W = 1200;
			const H = 630;
			const scale = Math.min(W / layout.width, H / layout.height, 1);
			const tx = (W - layout.width * scale) / 2;
			const ty = (H - layout.height * scale) / 2;

			const svg =
				`<svg xmlns="http://www.w3.org/2000/svg" width="${W}" height="${H}" viewBox="0 0 ${W} ${H}">` +
				`<style>${STYLE}</style>` +
				`<rect x="0" y="0" width="${W}" height="${H}" fill="${BG}"/>` +
				`<g transform="translate(${tx} ${ty}) scale(${scale})">` +
				inlineColors(body) +
				`</g></svg>`;

			const outPath = path.join(OUT, `graph-${e.hash}.png`);
			await rsvg(svg, outPath);
			if (toBuild) await copyFile(outPath, path.join(BUILD_OUT, `graph-${e.hash}.png`));
			done.add(e.hash);
		}
	}

	console.log(
		`gen-og-graphs: rasterised ${done.size} graph PNG(s) for ${favoritesWithFsm} FSM favorite(s)` +
			(skipped.length ? `, skipped ${skipped.length}: ${skipped.join(', ')}` : '')
	);
}

main().catch((err) => {
	console.error('gen-og-graphs: failed —', err);
	process.exit(0); // never fail the build
});
